<template>
    <el-submenu v-if="current.parentId===parentId && hasChild(current.id)" :index="String(current.id)">
        <template slot="title">
            <i v-if="+current.parentId===0" :class="current.icon || 'el-icon-menu'"></i>
            <span>{{current.title}}</span>
        </template>
        <sub-menu :menus="menus" v-for="i in menus" :key="i.id" :parent-id="current.id" :current="i"></sub-menu>
    </el-submenu>
    <el-menu-item v-else-if="current.parentId===parentId" :index="current.page.toLowerCase()">
        <i v-if="+current.parentId===0" :class="current.icon || 'el-icon-menu'"></i>
        <span slot="title">
            <el-badge :is-dot="current.id===1">
                {{current.title}}
            </el-badge>
        </span>
    </el-menu-item>
</template>
<script>
    export default {
        name: 'SubMenu',
        props: {
            menus: {type: Array, require: true},
            parentId: {type: Number, default: 0},
            current: {type: Object, require: true}
        },
        methods: {
            hasChild(id) {
                return this.menus.some(e => +e.parentId === +id);
            }
        },
    }
</script>
<style scoped>
    >>> .el-badge__content {
        border: none !important;
        margin-top: 10px;
        margin-right: -10px;
    }
</style>
