<template>
    <!-- 边栏组件 -->
    <el-aside class="hidden-sm-and-down" v-loading="loading" element-loading-background="rgba(0, 0, 0, 0.8)">
        <!-- logo -->
        <el-header></el-header>
        <!-- 菜单 -->
        <el-container>
            <el-menu text-color="hsla(0, 0%, 100%, .65)"
                     active-text-color="#fff"
                     :default-active="$store.state.route.name"
                     :collapse="collapse"
                     :collapse-transition="true"
                     :unique-opened="true"
                     @select="e => $router.push({name: e})">
                <div class="center">
                    <el-input v-if="!collapse"
                              v-model="search"
                              class="w-90"
                              placeholder="搜索菜单"
                              prefix-icon="el-icon-search"
                              clearable
                    ></el-input>
                </div>
                <sub-menu :menus="items" v-for="i in items" :key="i.id" :current="i"></sub-menu>
            </el-menu>
        </el-container>
        <!-- 底部伸缩按钮 -->
        <el-footer style="height: 40px; font-size: 20px">
            <i v-if="collapse" class="el-icon-s-unfold pointer" @click="collapseMenu"></i>
            <i v-else class="el-icon-s-fold pointer" @click="collapseMenu"></i>
        </el-footer>
        <!-- 移动端的抽屉菜单 -->
        <el-drawer :visible.sync="drawer" :with-header="false" direction="ltr" append-to-body :show-close="false" size="50%">
            <el-menu class="w-100 h-100"
                     text-color="hsla(0, 0%, 100%, .65)"
                     active-text-color="#fff"
                     :default-active="$store.state.activeIndex"
                     :collapse="false"
                     :collapse-transition="true"
                     :unique-opened="true"
                     @select="e => {
                         $router.push({name: e});
                         $store.commit('drawer', false);
                     }">
                <sub-menu :menus="items" v-for="i in items" :key="i.id" :current="i"></sub-menu>
            </el-menu>
        </el-drawer>
    </el-aside>
</template>
<script>
    import SubMenu from '@/components/layout/SubMenu'
    import {list} from "@/plugins/axios/api/menu";
    import CustomStorage from "@/plugins/common/CustomStorage";

    export default {
        data() {
            return {
                loading: false,
                collapse: !!+CustomStorage.getItem('_collapse_menu'),
                menus: [],
                search: null // 查询菜单
            }
        },
        methods: {
            listMenu() {
                this.loading = true;
                list().then(data => this.menus = data.records)
                    .finally(() => this.loading = false);
            },
            collapseMenu() {
                this.collapse = !this.collapse;
                CustomStorage.setItem('_collapse_menu', this.collapse ? '1' : '0');
            },
            findAllChildren(o) { // 找到所有子菜单
                let array = [];
                this.menus.filter(e => e.parentId === o.id).forEach(e => {
                    array = [e, ...array, ...this.findAllChildren(e)];
                });
                return array;
            },
            findAllParent(o) { // 找到所有父菜单
                let array = [];
                this.menus.filter(e => e.id === o.parentId).forEach(e => {
                    array = [e, ...array, ...this.findAllParent(e)];
                });
                return array;
            }
        },
        computed: {
            items() {
                /**
                 * 1.如果查询到的是最上级菜单, 需要查询出所有子菜单
                 * 2.如果查询到的是最下级菜单, 需要查询出所有父菜单
                 * 3.如果查询到的是中间级菜单, 需要查询出所有父菜单和子菜单
                 */
                if (this.search) {
                    let array = [];
                    this.menus.filter(e => e.title.indexOf(this.search) >= 0).forEach(e => {
                        array.push(e);
                        array = [...array, ...this.findAllChildren(e)];
                        array = [...array, ...this.findAllParent(e)];
                    });
                    return array;
                } else {
                    return this.menus;
                }
            },
            drawer: {
                get() {
                    return this.$store.state.drawer;
                },
                set(val) {
                    this.$store.commit('drawer', val);
                }
            }
        },
        components: {SubMenu},
        created() {
            this.listMenu();
        },
    }
</script>
<style scoped lang="less">
    @background-color: #001529;
    aside {
        width: auto !important;
        display: flex;
        flex-direction: column;
        overflow-x: hidden;
    }

    header, footer {
        background-color: @background-color;
        color: white;
    }

    /deep/ .el-menu {
        border: none;
        background-color: @background-color;

        &-item {
            background-color: @background-color;
        }

        &:not(.el-menu--collapse) {
            width: 192px;
        }
    }

    // input不要边框和阴影
    /deep/ .el-input__inner {
        border: none !important;

        &:focus {
            -webkit-box-shadow: none !important;
            box-shadow: none !important;
        }
    }

    /deep/ .el-drawer {
        overflow: scroll;
        background-color: @background-color;

        :focus {
            outline: none !important;
        }

        &::-webkit-scrollbar {
            display: none !important;
        }
    }

    /* 菜单元素高度、字体大小 */
    /deep/ .el-submenu__title,
    /deep/ .el-menu-item {
        min-width: inherit !important;
        display: flex;
        align-items: center;
        height: 40px;
        line-height: 40px;
        font-size: 14px !important;
        margin: 6px 0;
    }

    /deep/ .el-menu-item:hover, /* 鼠标悬浮菜单文字高亮 */
    /deep/ .el-submenu__title:hover, /* 鼠标悬浮母菜单文字高亮 */
    /deep/ .el-submenu.is-opened > .el-submenu__title, /* 展开的母菜单文字高亮 */
    /deep/ .el-submenu.is-active > .el-submenu__title { /* 激活菜单的母菜单文字高亮 */
        color: #fff !important;
    }

    /deep/ .el-menu-item:hover,
    /deep/ .el-submenu__title:hover { /*鼠标悬浮背景色*/
        background-color: #2c3e50 !important;
    }

    /* 当前激活菜单背景特殊颜色 */
    /deep/ .el-menu-item.is-active {
        background-color: #1890ff !important;
    }
</style>
