<template>
    <el-container style="height: inherit">
        <div>
            <el-breadcrumb class="hidden-sm-and-down">
                <el-breadcrumb-item v-for="i in breadcrumbs" :key="i.to" :to="{name:i.to}">{{i.name}}</el-breadcrumb-item>
            </el-breadcrumb>
            <i class="el-icon-s-unfold hidden-md-and-up pointer" @click="$store.commit('drawer', true)"></i>
        </div>
        <div>
            <el-button type="primary" circle icon="el-icon-user"></el-button>
            <el-button type="info" circle icon="el-icon-message"></el-button>
            <el-button type="warning" circle icon="el-icon-setting"></el-button>
            <el-button type="danger" circle icon="el-icon-switch-button" @click="$router.push({name:'login'})"></el-button>
        </div>
    </el-container>
</template>
<script>
    import {parseArray} from "@/plugins/common/Func";
    import CustomStorage from "@/plugins/common/CustomStorage";

    export default {
        data() {
            return {
                breadcrumbs: parseArray(CustomStorage.getItem('_breadcrumbs')),
                drawer: false,
                menus: []
            }
        },
        watch: {
            $route(to, from) {
                if (to.meta?.isMenu || from.name === 'main')
                    this.breadcrumbs = [];
                if (!this.breadcrumbs.some(e => e.to === to.name) && to.meta?.title)
                    this.breadcrumbs.push({to: to.name, name: to.meta?.title});
                CustomStorage.setItem('_breadcrumbs', JSON.stringify(this.breadcrumbs));
            }
        }
    }
</script>
<style scoped>
    section {
        display: flex;
        align-items: center;
        justify-content: space-between;
    }
</style>
