<template>
    <div>
        <el-tabs v-if="tabs.length > 0"
                 :value="$store.state.route.name"
                 type="card"
                 closable
                 @tab-click="e => $router.push({name: e.name})"
                 @tab-remove="remove"
        >
            <el-tab-pane v-for="i in tabs" :key="i.name" :name="i.name" :label="i.label"></el-tab-pane>
        </el-tabs>
    </div>
</template>
<script>
    import store from "@/plugins/vuex";
    import {parseArray} from "@/plugins/common/Func";
    import CustomStorage from "@/plugins/common/CustomStorage";

    export default {
        data() {
            return {
                tabs: parseArray(CustomStorage.getItem('_tabs'))
            }
        },
        methods: {
            remove(name) {
                if (this.tabs.length <= 1)
                    throw '最后一个标签无法关闭'
                // 如果关闭的是当前激活的tab，则切换到其它tab，优先级 右>左
                if (this.$route.name === name) {
                    let index = this.tabs.findIndex(e => e.name === name);
                    let nextIndex = this.tabs[index + 1]?.name || this.tabs[index - 1]?.name
                    if (nextIndex) {
                        this.$router.push({name: nextIndex});
                    } else {
                        store.commit('setActiveIndex', null); // 先清空，这样在push->main的时候就没有activeIndex了
                        this.$router.push({name: 'main'});
                    }
                }
                this.tabs = this.tabs.filter(e => e.name !== name);
            }
        },
        watch: {
            $route(to) {
                if (to.meta?.isMenu) {
                    store.commit('setActiveIndex', to.name);
                    // 添加tab
                    if (this.tabs.every(e => e.name !== to.name))
                        this.tabs.push({label: to.meta?.title, name: to.name});
                }
            },
            tabs(val) {
                CustomStorage.setItem('_tabs', JSON.stringify(val));
            }
        }
    }
</script>
<style scoped lang="less">
    ._height {
        height: auto;
        line-height: 26px;
    }

    /deep/ .el-tabs__item {
        ._height();
        font-size: ._height[line-height] * 0.5;
        padding: 0 ._height[line-height] * 0.5 !important;
    }

    /deep/ .el-tabs__nav- {
        &prev, &next {
            ._height();
        }
    }

    /deep/ .el-icon-close {
        margin-left: 0;
    }
</style>
